code.Java:
class Solution {
    public static boolean searchInBST(Node root, int x) {
        if (root == null) {
            return false;
        }

        if (root.val == x) {
            return true;
        }

        if (root.val > x)
            return searchInBST(root.left, x); 
        else 
            return searchInBST(root.right, x);
    }
}

