class Solution {
    searchInBST(root, x) {
        if (root === null) {
            return false;
        }

        if (root.val === x) {
            return true;
        }

        if (x < root.val) {
            return this.searchInBST(root.left, x);
        } else {
            return this.searchInBST(root.right, x);
        }
    }
}
